async function test\(\) {
  // PubMed
  try {
    const r1 = await fetch\('https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?db=pubmed&term=soybean+rust&retmax=3&retmode=json'\);
    const d1 = await r1.json\(\);
    console.log\('PubMed IDs:', d1.esearchresult.idlist\);

    const ids = d1.esearchresult.idlist.join\(','\);
    const r1b = await fetch\('https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esummary.fcgi?db=pubmed&id=' + ids + '&retmode=json'\);
    const d1b = await r1b.json\(\);
    const titles = d1.esearchresult.idlist.map\(id => d1b.result[id]?.title?.substring\(0, 60\)\);
    console.log\('PubMed titles:', titles\);
  } catch\(e\) { console.error\('PubMed error:', e.message\); }

  // CrossRef
  try {
    const r2 = await fetch\('https://api.crossref.org/works?query=soybean+rust+detection&rows=2'\);
    const d2 = await r2.json\(\);
    console.log\('CrossRef:', d2.message.items.map\(i => i.title?.[0]?.substring\(0, 60\)\)\);
  } catch\(e\) { console.error\('CrossRef error:', e.message\); }

  // Semantic Scholar  
  try {
    const r3 = await fetch\('https://api.semanticscholar.org/graph/v1/paper/search?query=soybean+rust&limit=2&fields=title,abstract,authors,year,citationCount,externalIds,url'\);
    console.log\('SemanticScholar status:', r3.status\);
    if \(r3.ok\) {
      const d3 = await r3.json\(\);
      console.log\('SemanticScholar:', d3.data?.map\(p => p.title?.substring\(0, 60\)\)\);
    }
  } catch\(e\) { console.error\('SemanticScholar error:', e.message\); }
}
test\(\);
